import{c as a,Q as o,j as r,m as e}from"./chunks/framework.DpF7k2f3.js";const m=JSON.parse('{"title":"제5장 LLM 호출과 프롬프트 엔지니어링","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part2-fundamentals/chapter5.md","filePath":"ko/part2-fundamentals/chapter5.md","lastUpdated":1779671667000}'),n={name:"ko/part2-fundamentals/chapter5.md"};function s(l,t,p,i,u,c){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="제5장-llm-호출과-프롬프트-엔지니어링" tabindex="-1">제5장 LLM 호출과 프롬프트 엔지니어링 <a class="header-anchor" href="#제5장-llm-호출과-프롬프트-엔지니어링" aria-label="Permalink to &quot;제5장 LLM 호출과 프롬프트 엔지니어링&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>축하합니다! 드디어 진짜 것을 시작합니다!</p><p>앞의 몇 챕터에서 많은 &quot;가상적인&quot; 것들에 대해 이야기했습니다 - 업계 인식, 입문 로드맵, 엔지니어링 기초. 이 챕터부터 AI 앱 개발의 <strong>핵심 기술 영역</strong>에 진입합니다.</p><p>이 챕터는 이 책의 가장 핵심적인 기술 챕터 중 하나입니다. 원본 내용에서는 기본 기술을 다루었지만, 솔직히 말하면 좀 얕았습니다 - &quot;젓가락 사용 방법&quot;만 가르치지만 &quot;转动丸子怎么夹&quot;는 가르치지 않는 것과 같습니다. 실전에서 정말 유용한 것들을 보충해 드리겠습니다.</p><p>이 챕터를 읽고 나면 가져갈 것들:</p><ul><li><strong>반석 같은 API 호출</strong>: 작동하면 그만인 것이 아니라, 높은 동시성을 처리하고, 스트리밍 출력을 처리하며, 모델이 실패할 때 우아하게降级</li><li><strong>체계적인 프롬프트 방법론</strong>: 트릭을 외우는 것이 아니라, 왜 이렇게 작성하면 효과적인지, 어떤 기술을いつ使用해야 하는지 이해</li><li><strong>프로덕션급 구조화된 출력</strong>: JSON Schema怎么做, 다중 레벨 중첩怎么处理, 정보 추출 파이프라인怎么搭建</li><li><strong>지능형 컨텍스트 관리</strong>: 대화 상태 머신, 의도 인식, 슬롯 채우기 - AI가 진정으로 &quot;이해&quot;하게 함</li><li><strong>실제 비용 관리</strong>: 이론이 아니라, 한 달에 얼마를 탔는지, 어떻게 절반으로 줄였는지에 대한 경험</li><li><strong>함정 밟은 피날레</strong>:踏んだ坑, 다시는踏ませたくない</li></ul><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter5.html">中文版阅读</a></p></blockquote>',9)])])}const _=a(n,[["render",s]]);export{m as __pageData,_ as default};
